package com.cho2hand.marketplace.service.impl.report;import com.cho2hand.marketplace.dto.report.CreateListingReportRequest;import com.cho2hand.marketplace.entity.report.ListingReport;import com.cho2hand.marketplace.exception.*;import com.cho2hand.marketplace.repository.listing.ListingRepository;import com.cho2hand.marketplace.repository.report.ListingReportRepository;import com.cho2hand.marketplace.service.report.ReportService;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service@Transactional public class ReportServiceImpl implements ReportService{private final ListingReportRepository reports;private final ListingRepository listings;private final com.cho2hand.marketplace.repository.report.ReportReasonRepository reasons;public ReportServiceImpl(ListingReportRepository r,ListingRepository l,com.cho2hand.marketplace.repository.report.ReportReasonRepository x){reports=r;listings=l;reasons=x;}public void reportListing(Long user,Long listing,CreateListingReportRequest r){listings.findById(listing).orElseThrow(()->new ListingNotFoundException(listing));if(reasons.findByIdAndActiveTrue(r.reasonId()).isEmpty())throw new LookupValueNotFoundException("Report reason",r.reasonId().toString());if(reports.existsByListingIdAndReporterUserIdAndReasonId(listing,user,r.reasonId()))throw new DuplicateReportException();var report=new ListingReport();report.setListingId(listing);report.setReporterUserId(user);report.setReasonId(r.reasonId());report.setDetails(r.details());reports.save(report);}}
